    gert::Shape *yShape = context->GetOutputShape(0);
    yShape->SetDimNum(3);
    yShape->SetDim(0, N);
    yShape->SetDim(1, Cout);
    yShape->SetDim(2, Lout);

    return GRAPH_SUCCESS;
}

